DEFAULT_TRANSPORT_PROTOCOL_SERVER = 'tcp://*'
DEFAULT_TRANSPORT_PROTOCOL_CLIENT = 'tcp://localhost'
if os.name == "nt":
    CFG_DRI = os.path.expanduser('~\\testerconfig')
else:
    CFG_DRI = os.path.expanduser('~/testerconfig')
CFG_FILE = os.path.join(CFG_DRI, 'config.json')

class Sequencer(object):

    def __init__(self, site, url, publisher, lock, stateEvent, syncEvent, mainEvent):
        super(Sequencer, self).__init__()
        self.site = int(site/10)
        self.sub_site = site%10
        self.sequence = None
        self.mux_lock = lock
        self.stateEvent = stateEvent
        self.syncEvent = syncEvent
        self.mainEvent = mainEvent
        self.publisher = publisher
        if url == DEFAULT_TRANSPORT_PROTOCOL_SERVER:
            transport_url = DEFAULT_TRANSPORT_PROTOCOL_CLIENT
            self.url = transport_url
        else:
            transport_url = url
            self.url = url
        
        engine_port = zmqports.TEST_ENGINE_PORT + int(site)

        self.test_engine = RPCClientWrapper(
            transport_url + ':' + str(engine_port),
            self.publisher
        )
        self.test_engine_proxy = self.test_engine.remote_server()

        self.pc = 0
        self.run_thread = None
        self.reporter = reporter.Reporter(self.publisher)
        self.plugin = PluginServer()
        self.error_msg = ''
        SequencerState.total_pass = True
        self.engine_delay = ENGINE_DELAY_MS
        self.customizer = None
        self._status = NONLOADED
        self.load_config(CFG_FILE)

    def load_config(self, config_file=CFG_FILE):
        path = os.path.join(os.path.split(__file__)[0], os.path.pardir, config_file)
        cfg = os.path.abspath(path)
        if os.path.exists(cfg):
            with open(cfg, 'r') as f:
                config = json.load(f)
            params = config.get('sequencer')
            self.engine_delay = params.get('engine_timeout', self.engine_delay)
            self.end_test_timeout = params.get('end_test_timeout', self.engine_delay)
            # load dimension identifier
            defaults = config.get('defaults')
            if defaults:
                dmns_tags = defaults.get('dmns_tags', None)
                if dmns_tags:
                    try:
                        identifier = 'dimension-{}'.format(self.sub_site)
                        self.dimension_id = dmns_tags[identifier]
                    except KeyError as e:
                        # print 'Invalid key for dimension identifier'
                        self.publisher.publish('Invalid key for dimension identifier', level=levels.INFO)
                        return False
            lib_path = params.get('customizer')
            if lib_path:
                try:
                    self.customizer = importlib.import_module(lib_path)
                    # print 'Imported customizer module from config.json'
                    self.publisher.publish('Imported customizer module from config.json', level=levels.INFO)
                    return True
                except ImportError as e:
                    # print 'Failed to import customizer module defined in config: '+e.message
                    self.publisher.publish('Failed to import customizer module defined in config: '+e.args[0], level=levels.CRITICAL)
        else:
            print ('Failed to locate config.json')
        if os.path.exists('customizer.py'):
            try:
                self.customizer = importlib.import_module('customizer')
                # print 'Imported customizer module from default location'
                self.publisher.publish('Imported customizer module from default location', level=levels.INFO)
                return True
            except ImportError as e:
                # print 'Failed to import local customizer module: ' + e.message
                self.publisher.publish('Failed to import local customizer module: ' + e.args[0], level=levels.CRITICAL)
        if self.customizer is None:
            # print 'No customizer module is found to import'
            self.publisher.publish('No customizer module is found to import', level=levels.INFO)
            return False

    def connect(self):
        """connect sequencer to test engine"""
        self.publisher.publish('connecting to test engine...', 'initializing', level=levels.INFO)
        response = self.test_engine.remote_server()._my_rpc_server_is_ready()
        if response and response.result == '--PASS--':
            self.publisher.publish('connected', level=levels.INFO)
            return True
        else:
            self.publisher.publish('failed to connect to test engine', level=levels.CRITICAL)
            return False

    def skip_to_next(self):
        """return value indicates if we have wrapped around"""
        if self.sequence:
            self._inc_pc()
            item = self.sequence[self.pc]
            return [self.pc+1, str(item)]

    def _inc_pc(self):
        """return value indicates if we have wrapped around"""
        if self.sequence:
            self.pc += 1
            if self.pc == len(self.sequence):
                self.pc = 0
                return True
        return False

    def load_sequence(self, sequence_db):
        self.sequence = TestSequence(sequence_db)
        self.pc = 0
        self.plugin.sequence = self.sequence
        # self.reporter.report(events.SEQUENCE_LOADED, name=os.path.basename(sequence_db).split('.')[0], case_list=self.s_list('all'))
        self.reporter.report(events.SEQUENCE_LOADED, name=os.path.basename(sequence_db).split('.')[0], path=sequence_db, case_list=self.s_list('all'))
        self._status = READY
        return sequence_db + ' has been loaded'

    def jump_to_line(self, line):
        if line > len(self.sequence) or line < 1:
            raise JSONRPCInvalidParamsError('the requested line ' + str(line) + ' is beyond the end of the sequence')
        self.pc = line - 1
        item = self.sequence[self.pc]
        return [self.pc+1, str(item)]

    def jump_to_name(self, name):
        try:
            item = self.sequence[name]
            if isinstance(item, TestGroup):
                item = item[0]
                self.pc = self.sequence.get_index(item.tid, group=name)
            else:
                self.pc = self.sequence.get_index(item.tid)
            return [self.pc+1, str(item)]
        except KeyError as e:
            raise JSONRPCInvalidParamsError(e.args[0])

    def s_jump(self, line):
        if self.sequence is None:
            raise JSONRPCInvalidRequestError('No sequence has been loaded. Load a valid sequence first')
        try:
            line = int(line)
            return self.jump_to_line(line)
        except ValueError:
            # if it's not an integer, assume it's a TID or group name
            return self.jump_to_name(line)

    def s_list(self, lines):
        if self.sequence is None:
            raise JSONRPCInvalidRequestError('Can not list. No sequence has been loaded. Load a valid sequence first')
        try:
            start = 0
            if lines.strip().lower() == 'all':
                stop = len(self.sequence)
            else:
                lines = int(lines)
                start = int(max(self.pc - lines/3, 0))
                stop = int(min(len(self.sequence), start + lines))
            reply = [[self.pc, start, stop]]
            # line is 1 based and pc is 0 based
            reply.extend([[i+1, str(self.sequence[i])] for i in range(start, stop)])
            return reply
        except ValueError as e:
            raise JSONRPCInvalidParamsError('in command list, ' + lines + ' is not an integer')

    # return True if the run timeout, return False if normal exit. If timeout is 0 then no timeout
    def wait(self, timeout):  # timeout is in seconds
        timeout = int(timeout)
        t1 = datetime.now()
        while self._status in [RUNNING, PAUSE]:
            if timeout != 0:
                t2 = datetime.now()
                elapsed = (t2-t1).total_seconds()
                if elapsed > timeout:
                    return True
            time.sleep(0.1)
        return False

